数组的易错点
好的代码习惯：一定要给数组进行初始化。
数组名不是变量！不能通过数组名直接给数组赋值！
int a[5];
cout<<a[0]<<a[1]<<a[2]<<a[3]<<a[4];
8 | 33 | 8331588 | 7470952 | 4236544
垃圾数据
int a[5] = {};
a = {1,2,3,4,5};

遍历数组元素
int a[5]={98,88,85,78,92};
// 正序遍历，输出数组元素
for(int i=0;i<5;i++) {
    cout << a[i] << " ";
}
cout << endl;
// 倒序遍历，输出数组元素
for(int i=4;i>=0;i--) {
    cout << a[i] << " ";
}
